// ============================================================
//  DARK / LIGHT THEME
// ============================================================
function getTheme() {
  return localStorage.getItem(DB_TEMA) || "light";
}

function applyTheme(theme, save = true) {
  const html = document.documentElement;
  if (theme === "dark") {
    html.setAttribute("data-bs-theme", "dark");
    html.classList.add("dark-mode");
  } else {
    html.setAttribute("data-bs-theme", "light");
    html.classList.remove("dark-mode");
  }
  if (save) localStorage.setItem(DB_TEMA, theme);
  updateThemeBtn(theme);
}

function updateThemeBtn(theme) {
  document.querySelectorAll(".theme-toggle").forEach((btn) => {
    btn.innerHTML =
      theme === "dark"
        ? '<i class="bi bi-sun-fill"></i>'
        : '<i class="bi bi-moon-fill"></i>';
  });
}

function toggleTheme() {
  const t = getTheme();
  applyTheme(t === "dark" ? "light" : "dark");
}

// Apply theme immediately
(function () {
  applyTheme(getTheme(), false);
})();

// ============================================================
//  AUTH
// ============================================================
function checkLogin() {
  if (
    !window.location.href.includes("login.html") &&
    sessionStorage.getItem("isLoggedIn") !== "true"
  ) {
    window.location.href = "login.html";
  }
}
checkLogin();

function doLogin(e) {
  if (e) e.preventDefault();
  const user = document.getElementById("loginUser")?.value.trim();
  const pass = document.getElementById("loginPass")?.value.trim();
  // Check multiple admins
  const admins = JSON.parse(localStorage.getItem(DB_ADMINS)) || [];
  const found = admins.find(
    (a) => a.username === user && a.password === pass
  );
  if (found) {
    sessionStorage.setItem("isLoggedIn", "true");
    sessionStorage.setItem("currentAdminId", found.id);
    sessionStorage.setItem("currentAdminUsername", found.username);
    // Sync legacy DB_ADMIN
    localStorage.setItem(DB_ADMIN, JSON.stringify(found));
    window.location.href = "dashboard.html";
  } else {
    showToast("Username atau password salah!", "danger");
    const el = document.getElementById("loginPass");
    if (el) {
      el.value = "";
      el.focus();
    }
  }
}

function doLogout() {
  showConfirm(
    "Keluar dari sistem?",
    "Anda akan diarahkan ke halaman login.",
    () => {
      sessionStorage.removeItem("isLoggedIn");
      window.location.href = "login.html";
    },
  );
}

// ============================================================
//  TOAST NOTIFICATION
// ============================================================
function showToast(msg, type = "success") {
  const iconMap = {
    success: "check-circle-fill",
    danger: "x-circle-fill",
    warning: "exclamation-triangle-fill",
    info: "info-circle-fill",
  };
  let container = document.getElementById("toastContainer");
  if (!container) {
    container = document.createElement("div");
    container.id = "toastContainer";
    container.style.cssText =
      "position:fixed;bottom:1rem;right:1rem;z-index:99999;display:flex;flex-direction:column;gap:8px;";
    document.body.appendChild(container);
  }
  const id = "toast_" + Date.now();
  const div = document.createElement("div");
  div.id = id;
  div.innerHTML = `
    <div class="toast align-items-center text-bg-${type} border-0 show" role="alert">
      <div class="d-flex">
        <div class="toast-body d-flex align-items-center gap-2">
          <i class="bi bi-${iconMap[type] || "info-circle-fill"}"></i> ${msg}
        </div>
        <button type="button" class="btn-close btn-close-white me-2 m-auto" onclick="this.closest('.toast').remove()"></button>
      </div>
    </div>`;
  container.appendChild(div);
  setTimeout(() => {
    div.querySelector(".toast")?.remove();
  }, 3500);
}

// ============================================================
//  CONFIRM DIALOG
// ============================================================
function showConfirm(title, msg, onOk) {
  let modal = document.getElementById("globalConfirmModal");
  if (!modal) {
    modal = document.createElement("div");
    modal.id = "globalConfirmModal";
    modal.className = "modal fade";
    modal.setAttribute("tabindex", "-1");
    modal.innerHTML = `
      <div class="modal-dialog modal-dialog-centered">
        <div class="modal-content">
          <div class="modal-header bg-danger text-white">
            <h5 class="modal-title"><i class="bi bi-exclamation-triangle-fill me-2"></i><span id="confirmTitle"></span></h5>
            <button type="button" class="btn-close btn-close-white" data-bs-dismiss="modal"></button>
          </div>
          <div class="modal-body"><p id="confirmMsg" class="mb-0"></p></div>
          <div class="modal-footer">
            <button class="btn btn-secondary" data-bs-dismiss="modal"><i class="bi bi-x-lg me-1"></i>Batal</button>
            <button id="confirmOkBtn" class="btn btn-danger"><i class="bi bi-check-lg me-1"></i>Ya, Lanjutkan</button>
          </div>
        </div>
      </div>`;
    document.body.appendChild(modal);
  }
  document.getElementById("confirmTitle").textContent = title;
  document.getElementById("confirmMsg").textContent = msg;
  const bsModal = new bootstrap.Modal(modal);
  bsModal.show();
  const okBtn = document.getElementById("confirmOkBtn");
  const newOk = okBtn.cloneNode(true);
  okBtn.parentNode.replaceChild(newOk, okBtn);
  newOk.onclick = () => {
    bsModal.hide();
    onOk();
  };
}

// ============================================================
//  SIDEBAR ACTIVE STATE
// ============================================================
function setActivePage(pageId) {
  document
    .querySelectorAll(".nav-sidebar .nav-link")
    .forEach((a) => a.classList.remove("active"));
  const el = document.getElementById(pageId);
  if (el) el.classList.add("active");
}

// ============================================================
//  LOAD NAVBAR USER INFO
// ============================================================
function getCurrentAdmin() {
  const adminId = sessionStorage.getItem("currentAdminId");
  const admins = JSON.parse(localStorage.getItem(DB_ADMINS)) || [];
  if (adminId) {
    const found = admins.find((a) => a.id === adminId);
    if (found) return found;
  }
  // Fallback
  if (admins.length > 0) return admins[0];
  return JSON.parse(localStorage.getItem(DB_ADMIN)) || {};
}

function loadUserInfo() {
  const acc = getCurrentAdmin();
  const name = acc.username || "Admin";
  const initial = name[0].toUpperCase();

  document
    .querySelectorAll(".nav-user-name")
    .forEach((el) => (el.textContent = name));
  document
    .querySelectorAll(".nav-user-initial")
    .forEach((el) => (el.textContent = initial));
  document.querySelectorAll(".nav-user-photo").forEach((el) => {
    if (acc.foto) {
      el.src = acc.foto;
      el.style.display = "block";
      el.nextElementSibling && (el.nextElementSibling.style.display = "none");
    }
  });
  document
    .querySelectorAll(".sidebar-user-name")
    .forEach((el) => (el.textContent = name));
  document
    .querySelectorAll(".sidebar-user-role")
    .forEach((el) => (el.textContent = acc.nama_lengkap || "Administrator"));
  applyTheme(getTheme(), false);
}

// ============================================================
//  KELOLA AKUN ADMIN
// ============================================================
function openModalAkun() {
  const acc = getCurrentAdmin();
  const el = (id) => document.getElementById(id);
  if (el("akunUsername")) el("akunUsername").value = acc.username || "";
  if (el("akunNamaLengkap"))
    el("akunNamaLengkap").value = acc.nama_lengkap || "";
  if (el("akunEmail")) el("akunEmail").value = acc.email || "";
  if (el("akunPassword")) el("akunPassword").value = "";
  if (el("akunPassKonfirm")) el("akunPassKonfirm").value = "";

  const preview = el("akunFotoPreview");
  if (preview) {
    if (acc.foto) {
      preview.src = acc.foto;
      preview.style.display = "block";
    } else preview.style.display = "none";
  }
  const inisialEl = el("akunFotoInisial");
  if (inisialEl) inisialEl.textContent = (acc.username || "A")[0].toUpperCase();

  const m = bootstrap.Modal.getOrCreateInstance(
    document.getElementById("modalAkun"),
  );
  m.show();
}

function previewFotoAkun(input) {
  const file = input.files[0];
  if (!file) return;
  if (file.size > 2 * 1024 * 1024) {
    showToast("Foto max 2MB!", "warning");
    return;
  }
  const reader = new FileReader();
  reader.onload = (e) => {
    const prev = document.getElementById("akunFotoPreview");
    const init = document.getElementById("akunFotoInisial");
    if (prev) {
      prev.src = e.target.result;
      prev.style.display = "block";
    }
    if (init) init.style.display = "none";
  };
  reader.readAsDataURL(file);
}

function simpanAkun() {
  const el = (id) => document.getElementById(id);
  const username = el("akunUsername")?.value.trim();
  const namaLengkap = el("akunNamaLengkap")?.value.trim();
  const email = el("akunEmail")?.value.trim();
  const pass = el("akunPassword")?.value.trim();
  const passKonfirm = el("akunPassKonfirm")?.value.trim();
  const fotoInput = el("akunFotoInput");

  if (!username) {
    showToast("Username wajib diisi!", "danger");
    return;
  }
  if (pass && pass.length < 5) {
    showToast("Password min 5 karakter!", "warning");
    return;
  }
  if (pass && pass !== passKonfirm) {
    showToast("Konfirmasi password tidak cocok!", "danger");
    return;
  }

  const acc = getCurrentAdmin();

  function doSave(foto) {
    const updated = {
      ...acc,
      username,
      nama_lengkap: namaLengkap || username,
      email: email || "",
      password: pass || acc.password,
      foto: foto || acc.foto || null,
    };
    // Update in admins list
    const admins = JSON.parse(localStorage.getItem(DB_ADMINS)) || [];
    const idx = admins.findIndex((a) => a.id === acc.id);
    if (idx !== -1) {
      admins[idx] = updated;
      localStorage.setItem(DB_ADMINS, JSON.stringify(admins));
    }
    localStorage.setItem(DB_ADMIN, JSON.stringify(updated));
    bootstrap.Modal.getInstance(document.getElementById("modalAkun"))?.hide();
    loadUserInfo();
    showToast("Profil admin berhasil diperbarui!", "success");
    if (pass) {
      setTimeout(() => {
        showToast("Password diubah. Login ulang diperlukan.", "info");
        setTimeout(() => {
          sessionStorage.removeItem("isLoggedIn");
          window.location.href = "login.html";
        }, 2000);
      }, 800);
    }
  }

  if (fotoInput?.files[0]) {
    const r = new FileReader();
    r.onload = (e) => doSave(e.target.result);
    r.readAsDataURL(fotoInput.files[0]);
  } else doSave(null);
}

// ============================================================
//  MULTI-ADMIN CRUD
// ============================================================
function getAdmins() {
  return JSON.parse(localStorage.getItem(DB_ADMINS)) || [];
}
function saveAdmins(list) {
  localStorage.setItem(DB_ADMINS, JSON.stringify(list));
}

function renderTabelAdmin() {
  const tbody = document.getElementById("bodyAdmin");
  if (!tbody) return;
  const admins = getAdmins();
  const currentId = sessionStorage.getItem("currentAdminId");
  if (!admins.length) {
    tbody.innerHTML = `<tr><td colspan="5" class="text-center py-4 text-muted"><i class="bi bi-people fs-2 d-block mb-2"></i>Tidak ada admin</td></tr>`;
    return;
  }
  tbody.innerHTML = admins
    .map(
      (a, i) => `<tr class="${a.id === currentId ? "table-primary" : ""}">
    <td>${i + 1}</td>
    <td><strong>${a.username}</strong>${a.id === currentId ? ' <span class="badge bg-primary ms-1">Aktif</span>' : ""}</td>
    <td>${a.nama_lengkap || "-"}</td>
    <td>${a.email || "-"}</td>
    <td class="text-center">
      <button class="btn btn-sm btn-warning me-1" onclick="openEditAdmin('${a.id}')"><i class="bi bi-pencil-fill"></i></button>
      <button class="btn btn-sm btn-danger" onclick="hapusAdmin('${a.id}','${a.username}')" ${admins.length <= 1 ? "disabled" : ""}><i class="bi bi-trash-fill"></i></button>
    </td>
  </tr>`,
    )
    .join("");
}

function tambahAdmin() {
  const el = (id) => document.getElementById(id);
  const username = el("newAdminUsername")?.value.trim();
  const password = el("newAdminPassword")?.value.trim();
  const namaLengkap = el("newAdminNama")?.value.trim();
  const email = el("newAdminEmail")?.value.trim();

  if (!username) { showToast("Username wajib diisi!", "danger"); return; }
  if (!password || password.length < 5) { showToast("Password min 5 karakter!", "warning"); return; }

  const admins = getAdmins();
  if (admins.find((a) => a.username.toLowerCase() === username.toLowerCase())) {
    showToast("Username sudah digunakan!", "warning");
    return;
  }
  admins.push({
    id: "admin_" + Date.now(),
    username,
    password,
    nama_lengkap: namaLengkap || username,
    email: email || "",
    foto: null,
    role: "admin",
  });
  saveAdmins(admins);
  el("newAdminUsername").value = "";
  el("newAdminPassword").value = "";
  if (el("newAdminNama")) el("newAdminNama").value = "";
  if (el("newAdminEmail")) el("newAdminEmail").value = "";
  renderTabelAdmin();
  showToast(`Admin "${username}" berhasil ditambahkan!`, "success");
}

let editAdminId = null;
function openEditAdmin(id) {
  const admins = getAdmins();
  const a = admins.find((x) => x.id === id);
  if (!a) return;
  editAdminId = id;
  const el = (k) => document.getElementById(k);
  el("editAdminUsername").value = a.username;
  el("editAdminNama").value = a.nama_lengkap || "";
  el("editAdminEmail").value = a.email || "";
  el("editAdminPassword").value = "";
  new bootstrap.Modal(document.getElementById("modalEditAdmin")).show();
}

function simpanEditAdmin() {
  const el = (id) => document.getElementById(id);
  const username = el("editAdminUsername")?.value.trim();
  const namaLengkap = el("editAdminNama")?.value.trim();
  const email = el("editAdminEmail")?.value.trim();
  const pass = el("editAdminPassword")?.value.trim();

  if (!username) { showToast("Username wajib diisi!", "danger"); return; }
  if (pass && pass.length < 5) { showToast("Password min 5 karakter!", "warning"); return; }

  const admins = getAdmins();
  const dup = admins.find(
    (a) => a.username.toLowerCase() === username.toLowerCase() && a.id !== editAdminId
  );
  if (dup) { showToast("Username sudah digunakan admin lain!", "warning"); return; }

  const idx = admins.findIndex((a) => a.id === editAdminId);
  if (idx !== -1) {
    admins[idx] = {
      ...admins[idx],
      username,
      nama_lengkap: namaLengkap || username,
      email: email || "",
      ...(pass ? { password: pass } : {}),
    };
    saveAdmins(admins);
    // Update session if editing current admin
    const curId = sessionStorage.getItem("currentAdminId");
    if (editAdminId === curId) {
      sessionStorage.setItem("currentAdminUsername", username);
      localStorage.setItem(DB_ADMIN, JSON.stringify(admins[idx]));
      loadUserInfo();
    }
    bootstrap.Modal.getInstance(document.getElementById("modalEditAdmin"))?.hide();
    renderTabelAdmin();
    showToast("Admin berhasil diperbarui!", "success");
    if (pass && editAdminId === curId) {
      setTimeout(() => {
        showToast("Password diubah. Login ulang.", "info");
        setTimeout(() => {
          sessionStorage.removeItem("isLoggedIn");
          window.location.href = "login.html";
        }, 1500);
      }, 800);
    }
  }
}

function hapusAdmin(id, username) {
  const admins = getAdmins();
  if (admins.length <= 1) {
    showToast("Minimal harus ada 1 admin!", "warning");
    return;
  }
  showConfirm("Hapus Admin?", `Admin "${username}" akan dihapus permanen.`, () => {
    const updated = admins.filter((a) => a.id !== id);
    saveAdmins(updated);
    renderTabelAdmin();
    showToast(`Admin "${username}" dihapus.`, "info");
  });
}

// ============================================================
//  MANAJEMEN PENGELUARAN
// ============================================================
function getPengeluaran() {
  return JSON.parse(localStorage.getItem(DB_PENGELUARAN)) || [];
}
function savePengeluaran(data) {
  localStorage.setItem(DB_PENGELUARAN, JSON.stringify(data));
}

function renderTabelPengeluaran(filter = "hari_ini") {
  const tbody = document.getElementById("bodyPengeluaran");
  if (!tbody) return;

  let data = getPengeluaran();
  const now = new Date();

  // Filter by date range
  if (filter === "hari_ini") {
    const today = now.toLocaleDateString("id-ID");
    data = data.filter((p) => new Date(p.tanggal).toLocaleDateString("id-ID") === today);
  } else if (filter === "minggu_ini") {
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    data = data.filter((p) => new Date(p.tanggal) >= startOfWeek);
  } else if (filter === "bulan_ini") {
    data = data.filter((p) => {
      const d = new Date(p.tanggal);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
  } else if (filter === "tahun_ini") {
    data = data.filter((p) => new Date(p.tanggal).getFullYear() === now.getFullYear());
  }
  // "semua" = no filter

  const totalEl = document.getElementById("totalPengeluaran");
  const total = data.reduce((s, p) => s + p.jumlah, 0);
  if (totalEl) totalEl.textContent = `Rp ${total.toLocaleString("id-ID")}`;

  const countEl = document.getElementById("countPengeluaran");
  if (countEl) countEl.textContent = data.length;

  if (!data.length) {
    tbody.innerHTML = `<tr><td colspan="6" class="text-center py-4 text-muted"><i class="bi bi-wallet2 fs-2 d-block mb-2"></i>Belum ada pengeluaran</td></tr>`;
    return;
  }
  tbody.innerHTML = data
    .map(
      (p, i) => `<tr>
    <td>${i + 1}</td>
    <td>${new Date(p.tanggal).toLocaleDateString("id-ID", { day: "2-digit", month: "short", year: "numeric" })}</td>
    <td><strong>${p.keterangan}</strong></td>
    <td><span class="badge ${p.kategori === 'Pembelian Stok' ? 'bg-success' : 'bg-info text-dark'}">${p.kategori === 'Pembelian Stok' ? '🛒 ' : ''}${p.kategori || "Umum"}</span></td>
    <td>${p.kategori === 'Pembelian Stok' && p.stokProdukNama ? `<span class="badge bg-success bg-opacity-75"><i class="bi bi-box-seam-fill me-1"></i>${p.stokProdukNama} <span class="badge bg-white text-success ms-1">+${p.stokJumlah}</span></span>` : '<span class="text-muted small">—</span>'}</td>
    <td class="text-end fw-bold text-danger">Rp ${p.jumlah.toLocaleString("id-ID")}</td>
    <td class="text-center">
      <button class="btn btn-sm btn-warning me-1" onclick="openEditPengeluaran('${p.id}')"><i class="bi bi-pencil-fill"></i></button>
      <button class="btn btn-sm btn-danger" onclick="hapusPengeluaran('${p.id}')"><i class="bi bi-trash-fill"></i></button>
    </td>
  </tr>`,
    )
    .join("");
}

function tambahPengeluaran() {
  const el = (id) => document.getElementById(id);
  const keterangan = el("newPKeterangan")?.value.trim();
  const jumlah = parseInt(el("newPJumlah")?.value) || 0;
  const kategori = el("newPKategori")?.value || "Umum";
  const tanggal = el("newPTanggal")?.value || new Date().toISOString().split("T")[0];

  if (!keterangan) { showToast("Keterangan wajib diisi!", "danger"); return; }
  if (jumlah <= 0) { showToast("Jumlah harus > 0!", "danger"); return; }

  // Validasi & proses sinkron stok jika kategori Pembelian Stok
  let stokProdukId = null, stokProdukNama = null, stokJumlah = 0;
  if (kategori === "Pembelian Stok") {
    stokProdukId = el("newPStokProduk")?.value;
    stokJumlah = parseInt(el("newPStokJumlah")?.value) || 0;
    if (!stokProdukId) { showToast("Pilih produk untuk sinkron stok!", "danger"); return; }
    if (stokJumlah <= 0) { showToast("Jumlah stok masuk harus > 0!", "danger"); return; }
    // Update stok produk
    const produk = getProducts();
    const idx = produk.findIndex((p) => p.id === stokProdukId);
    if (idx !== -1) {
      stokProdukNama = produk[idx].nama;
      produk[idx].stok = (produk[idx].stok || 0) + stokJumlah;
      saveProducts(produk);
      showToast(`Stok ${stokProdukNama} bertambah +${stokJumlah}!`, "success");
    }
  }

  const data = getPengeluaran();
  data.unshift({
    id: "PE-" + Date.now(),
    keterangan,
    jumlah,
    kategori,
    tanggal: new Date(tanggal).toISOString(),
    waktu: new Date().toLocaleString("id-ID"),
    stokProdukId,
    stokProdukNama,
    stokJumlah: stokJumlah || 0,
  });
  savePengeluaran(data);
  el("newPKeterangan").value = "";
  el("newPJumlah").value = "";
  if (el("newPStokJumlah")) el("newPStokJumlah").value = "";
  if (el("newPStokProduk")) el("newPStokProduk").value = "";
  if (el("newPStokSaatIni")) el("newPStokSaatIni").value = "";
  const filterEl = document.getElementById("filterPengeluaran");
  const activeFilter = filterEl?.value || "hari_ini";
  renderTabelPengeluaran(activeFilter);
  if (kategori !== "Pembelian Stok") showToast("Pengeluaran berhasil dicatat!", "success");
}

let editPengeluaranId = null;
function openEditPengeluaran(id) {
  const p = getPengeluaran().find((x) => x.id === id);
  if (!p) return;
  editPengeluaranId = id;
  const el = (k) => document.getElementById(k);
  el("editPKeterangan").value = p.keterangan;
  el("editPJumlah").value = p.jumlah;
  el("editPKategori").value = p.kategori || "Umum";
  el("editPTanggal").value = new Date(p.tanggal).toISOString().split("T")[0];
  // Tampilkan info stok jika kategori Pembelian Stok
  if (p.kategori === "Pembelian Stok" && p.stokProdukNama) {
    el("editPStokProdukNama").value = p.stokProdukNama;
    el("editPStokJumlahInfo").value = "+" + (p.stokJumlah || 0) + " unit";
    const panel = document.getElementById("panelStokEdit");
    if (panel) panel.style.setProperty("display", "flex", "important");
  } else {
    const panel = document.getElementById("panelStokEdit");
    if (panel) panel.style.setProperty("display", "none", "important");
  }
  new bootstrap.Modal(document.getElementById("modalEditPengeluaran")).show();
}

function simpanEditPengeluaran() {
  const el = (id) => document.getElementById(id);
  const keterangan = el("editPKeterangan")?.value.trim();
  const jumlah = parseInt(el("editPJumlah")?.value) || 0;
  const kategori = el("editPKategori")?.value || "Umum";
  const tanggal = el("editPTanggal")?.value;

  if (!keterangan) { showToast("Keterangan wajib!", "danger"); return; }
  if (jumlah <= 0) { showToast("Jumlah harus > 0!", "danger"); return; }

  const data = getPengeluaran();
  const idx = data.findIndex((p) => p.id === editPengeluaranId);
  if (idx !== -1) {
    data[idx] = { ...data[idx], keterangan, jumlah, kategori, tanggal: new Date(tanggal).toISOString() };
    savePengeluaran(data);
    bootstrap.Modal.getInstance(document.getElementById("modalEditPengeluaran"))?.hide();
    const filterEl = document.getElementById("filterPengeluaran");
    renderTabelPengeluaran(filterEl?.value || "hari_ini");
    showToast("Pengeluaran diperbarui!", "success");
  }
}

function hapusPengeluaran(id) {
  showConfirm("Hapus Pengeluaran?", "Data pengeluaran ini akan dihapus.", () => {
    savePengeluaran(getPengeluaran().filter((p) => p.id !== id));
    const filterEl = document.getElementById("filterPengeluaran");
    renderTabelPengeluaran(filterEl?.value || "hari_ini");
    showToast("Pengeluaran dihapus.", "info");
  });
}

function eksporPengeluaranExcel() {
  if (typeof XLSX === "undefined") { showToast("Library XLSX tidak tersedia!", "warning"); return; }
  const data = getPengeluaran();
  if (!data.length) { showToast("Tidak ada data!", "warning"); return; }
  const rows = [
    ["No", "Tanggal", "Keterangan", "Kategori", "Produk Stok", "Jumlah Stok", "Jumlah (Rp)"],
    ...data.map((p, i) => [
      i + 1,
      new Date(p.tanggal).toLocaleDateString("id-ID"),
      p.keterangan,
      p.kategori || "Umum",
      p.stokProdukNama || "-",
      p.stokJumlah || 0,
      p.jumlah,
    ]),
  ];
  const ws = XLSX.utils.aoa_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Pengeluaran");
  XLSX.writeFile(wb, `Pengeluaran_MingMart_${new Date().toLocaleDateString("id-ID").replace(/\//g, "-")}.xlsx`);
  showToast("Ekspor Excel pengeluaran berhasil!", "success");
}

// ============================================================
//  SINKRON STOK — Helper untuk Pembelian Stok
// ============================================================
function toggleStokFields(kategori, mode) {
  const panelId = mode === "new" ? "panelStokNew" : "panelStokEdit";
  const panel = document.getElementById(panelId);
  if (!panel) return;
  if (kategori === "Pembelian Stok") {
    panel.style.setProperty("display", "flex", "important");
    if (mode === "new") populateStokDropdown();
  } else {
    panel.style.setProperty("display", "none", "important");
  }
}

function populateStokDropdown() {
  // Legacy: populate hidden select (still needed for form submit logic)
  const sel = document.getElementById("newPStokProduk");
  if (!sel) return;
  const produk = getProducts();
  sel.innerHTML = '<option value="">— Pilih produk —</option>' +
    produk.map(p => `<option value="${p.id}">[${p.stok} ${p.satuan||'pcs'}] ${p.nama}</option>`).join("");
  // Init combobox display
  showStokDropdown();
}

function showStokDropdown() {
  const kw = document.getElementById("searchStokProduk")?.value || "";
  const dl = document.getElementById("stokDropdownList");
  if (!dl) return;
  const produk = getProducts();
  let filtered = produk;
  if (kw.length > 0) {
    const k = kw.toLowerCase();
    filtered = produk.filter(p =>
      p.nama.toLowerCase().includes(k) ||
      (p.kategori||"").toLowerCase().includes(k) ||
      p.id.toLowerCase().includes(k)
    );
  }
  if (filtered.length === 0) {
    dl.innerHTML = `<div class="px-3 py-2 text-muted small"><i class="bi bi-search me-1"></i>${kw ? `"${kw}" tidak ditemukan` : "Belum ada produk"}</div>`;
  } else {
    dl.innerHTML = filtered.map(p => `
      <div class="px-3 py-2 d-flex justify-content-between align-items-center"
           style="cursor:pointer;border-bottom:1px solid #f0f0f0"
           onmousedown="selectStokProduk('${p.id}')"
           onmouseover="this.style.background='#f0fff4'"
           onmouseout="this.style.background=''">
        <div>
          <div class="fw-semibold small">${p.nama}</div>
          <div class="text-muted" style="font-size:0.78rem">${p.kategori||""}</div>
        </div>
        <div class="text-end">
          <span class="badge bg-success bg-opacity-75" style="font-size:0.72rem">Stok: ${p.stok} ${p.satuan||'pcs'}</span>
        </div>
      </div>`).join("");
  }
  dl.classList.remove("d-none");
}

function filterStokProduk() {
  showStokDropdown();
  // Clear selection
  const sel = document.getElementById("newPStokProduk");
  if (sel) sel.value = "";
  const info = document.getElementById("newPStokSaatIni");
  if (info) info.value = "";
}

function selectStokProduk(id) {
  const p = getProducts().find(x => x.id === id);
  if (!p) return;
  // Set hidden select
  const sel = document.getElementById("newPStokProduk");
  if (sel) sel.value = id;
  // Set input text
  const inp = document.getElementById("searchStokProduk");
  if (inp) inp.value = p.nama;
  // Update stok info
  const info = document.getElementById("newPStokSaatIni");
  if (info) info.value = `${p.stok} ${p.satuan||'pcs'} (tersedia)`;
  // Show badge terpilih
  const badge = document.getElementById("stokProdukTerpilih");
  const namaEl = document.getElementById("stokProdukTerpilihNama");
  if (badge) badge.classList.remove("d-none");
  if (namaEl) namaEl.textContent = `${p.nama} — Stok: ${p.stok} ${p.satuan||'pcs'}`;
  // Hide dropdown
  const dl = document.getElementById("stokDropdownList");
  if (dl) dl.classList.add("d-none");
  // Focus jumlah stok
  document.getElementById("newPStokJumlah")?.focus();
}

function clearStokProduk() {
  const inp = document.getElementById("searchStokProduk");
  if (inp) inp.value = "";
  const sel = document.getElementById("newPStokProduk");
  if (sel) sel.value = "";
  const info = document.getElementById("newPStokSaatIni");
  if (info) info.value = "";
  const badge = document.getElementById("stokProdukTerpilih");
  if (badge) badge.classList.add("d-none");
  const dl = document.getElementById("stokDropdownList");
  if (dl) dl.classList.add("d-none");
  inp?.focus();
}

// ============================================================
//  IMPORT EXCEL FUNCTIONS
// ============================================================
function importProdukExcel(input) {
  if (typeof XLSX === "undefined") { showToast("Library XLSX tidak tersedia!", "warning"); return; }
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const wb = XLSX.read(e.target.result, { type: "binary" });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { header: 1 });
      if (rows.length < 2) { showToast("File kosong atau format salah!", "warning"); return; }

      const produk = getProducts();
      let added = 0, updated = 0;
      // Skip header row
      for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        if (!row || !row[2]) continue; // nama harus ada (col index 2)
        const nama = String(row[2]).trim();
        const harga = parseInt(row[4]) || 0;
        const stok = parseInt(row[5]) || 0;
        const kategori = row[3] ? String(row[3]).trim() : "Lainnya";
        const satuan = row[6] ? String(row[6]).trim() : "pcs";
        if (!nama || harga <= 0) continue;
        const existing = produk.findIndex((p) => p.nama.toLowerCase() === nama.toLowerCase());
        if (existing !== -1) {
          produk[existing] = { ...produk[existing], harga, stok, kategori, satuan };
          updated++;
        } else {
          produk.push({ id: "P" + String(Date.now() + i).slice(-6), nama, harga, stok, kategori, satuan });
          added++;
        }
      }
      saveProducts(produk);
      renderTabelProduk();
      updateStatProduk();
      showToast(`Import berhasil! Ditambah: ${added}, Diperbarui: ${updated}`, "success");
      input.value = "";
    } catch (err) {
      showToast("Gagal baca file Excel: " + err.message, "danger");
    }
  };
  reader.readAsBinaryString(file);
}

function importHutangExcel(input) {
  if (typeof XLSX === "undefined") { showToast("Library XLSX tidak tersedia!", "warning"); return; }
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const wb = XLSX.read(e.target.result, { type: "binary" });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { header: 1 });
      if (rows.length < 2) { showToast("File kosong!", "warning"); return; }

      const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
      let added = 0;
      for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        if (!row || !row[1]) continue; // pembeli harus ada
        const pembeli = String(row[1]).trim();
        const total = parseInt(row[3]) || 0;
        const status = row[4] ? String(row[4]).trim() : "Belum Lunas";
        const catatan = row[5] ? String(row[5]).trim() : "";
        if (!pembeli || total <= 0) continue;
        hutang.unshift({
          id: "HT-" + (Date.now() + i),
          trxId: "",
          pembeli,
          total,
          waktu: new Date().toLocaleString("id-ID"),
          status,
          catatan,
        });
        added++;
      }
      localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
      renderTabelHutang();
      showToast(`Import hutang berhasil! ${added} data diimpor.`, "success");
      input.value = "";
    } catch (err) {
      showToast("Gagal baca file Excel: " + err.message, "danger");
    }
  };
  reader.readAsBinaryString(file);
}

function importLaporanExcel(input) {
  if (typeof XLSX === "undefined") { showToast("Library XLSX tidak tersedia!", "warning"); return; }
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const wb = XLSX.read(e.target.result, { type: "binary" });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { header: 1 });
      if (rows.length < 2) { showToast("File kosong!", "warning"); return; }

      const riwayat = JSON.parse(localStorage.getItem(DB_RIWAYAT)) || [];
      let added = 0;
      for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        if (!row || !row[1]) continue; // waktu harus ada
        const waktu = String(row[1]).trim();
        const idTrx = row[0] ? String(row[0]).trim() : ("TRX-IMP-" + (Date.now() + i));
        const pembeli = row[2] ? String(row[2]).trim() : "-";
        const metode = row[3] ? String(row[3]).trim() : "Tunai";
        const total = parseInt(row[4]) || 0;
        if (!total) continue;
        // Skip if ID exists
        if (riwayat.find((t) => t.id === idTrx)) continue;
        riwayat.unshift({
          id: idTrx,
          waktu,
          pembeli,
          metode,
          total,
          diskon: parseInt(row[5]) || 0,
          items: [],
        });
        added++;
      }
      localStorage.setItem(DB_RIWAYAT, JSON.stringify(riwayat));
      if (typeof renderDashboard === "function") renderDashboard();
      showToast(`Import laporan berhasil! ${added} transaksi diimpor.`, "success");
      input.value = "";
    } catch (err) {
      showToast("Gagal baca file Excel: " + err.message, "danger");
    }
  };
  reader.readAsBinaryString(file);
}

// ============================================================
//  PRODUK CRUD
// ============================================================
let editProdukId = null;

function getProducts() {
  return JSON.parse(localStorage.getItem(DB_PRODUK)) || [];
}
function saveProducts(p) {
  localStorage.setItem(DB_PRODUK, JSON.stringify(p));
}

function getKategori() {
  return JSON.parse(localStorage.getItem(DB_KATEGORI)) || [];
}
function saveKategori(k) {
  localStorage.setItem(DB_KATEGORI, JSON.stringify(k));
}

function renderKategoriOptions(selectId, selected = "") {
  const kat = getKategori();
  const el = document.getElementById(selectId);
  if (!el) return;
  el.innerHTML = kat
    .map(
      (k) =>
        `<option value="${k}" ${k === selected ? "selected" : ""}>${k}</option>`,
    )
    .join("");
}

function renderTabelProduk(keyword = "", filterKat = "") {
  const tbody = document.getElementById("bodyProduk");
  if (!tbody) return;
  let produk = getProducts();
  if (keyword)
    produk = produk.filter(
      (p) =>
        p.nama.toLowerCase().includes(keyword.toLowerCase()) ||
        p.id.toLowerCase().includes(keyword.toLowerCase()),
    );
  if (filterKat) produk = produk.filter((p) => p.kategori === filterKat);

  if (!produk.length) {
    tbody.innerHTML = `<tr><td colspan="8" class="text-center py-4 text-muted"><i class="bi bi-inbox fs-1 d-block mb-2"></i>${keyword ? "Produk tidak ditemukan" : "Belum ada produk"}</td></tr>`;
    return;
  }
  tbody.innerHTML = produk
    .map(
      (p, i) => `
    <tr>
      <td>${i + 1}</td>
      <td><span class="badge bg-primary">${p.id}</span></td>
      <td><strong>${p.nama}</strong></td>
      <td><span class="badge bg-info text-dark">${p.kategori || "-"}</span></td>
      <td class="text-end fw-bold">Rp ${p.harga.toLocaleString("id-ID")}</td>
      <td class="text-center">
        <span class="badge ${p.stok <= 0 ? "bg-danger" : p.stok <= 5 ? "bg-warning text-dark" : "bg-success"}">${p.stok} ${p.satuan || "pcs"}</span>
      </td>
      <td class="text-center">
        <button class="btn btn-sm btn-warning me-1" onclick="openEditProduk('${p.id}')"><i class="bi bi-pencil-fill"></i></button>
        <button class="btn btn-sm btn-danger" onclick="hapusProduk('${p.id}','${p.nama.replace(/'/g, "\\'")}')"><i class="bi bi-trash-fill"></i></button>
      </td>
    </tr>`,
    )
    .join("");
}

function updateStatProduk() {
  const produk = getProducts();
  const low = produk.filter((p) => p.stok <= 5).length;
  const el = document.getElementById("statProduk");
  if (el)
    el.innerHTML = `<span class="badge bg-primary me-1">${produk.length} produk</span>${low > 0 ? `<span class="badge bg-danger">${low} stok rendah</span>` : `<span class="badge bg-success">Stok normal</span>`}`;
}

function tambahProduk() {
  const el = (id) => document.getElementById(id);
  const nama = el("newNama")?.value.trim();
  const harga = parseInt(el("newHarga")?.value) || 0;
  const stok = parseInt(el("newStok")?.value) || 0;
  const kat = el("newKategori")?.value || "Lainnya";
  const sat = el("newSatuan")?.value || "pcs";

  if (!nama) {
    showToast("Nama produk wajib diisi!", "danger");
    return;
  }
  if (harga <= 0) {
    showToast("Harga harus lebih dari 0!", "danger");
    return;
  }

  const produk = getProducts();
  const id = "P" + String(Date.now()).slice(-6);
  produk.push({ id, nama, harga, stok, kategori: kat, satuan: sat });
  saveProducts(produk);
  ["newNama", "newHarga"].forEach((i) => {
    const e = el(i);
    if (e) e.value = "";
  });
  if (el("newStok")) el("newStok").value = "0";
  renderTabelProduk();
  updateStatProduk();
  showToast(`Produk "${nama}" berhasil ditambahkan!`, "success");
}

function openEditProduk(id) {
  const p = getProducts().find((x) => x.id === id);
  if (!p) return;
  editProdukId = id;
  const el = (k) => document.getElementById(k);
  el("editNama").value = p.nama;
  el("editHarga").value = p.harga;
  el("editStok").value = p.stok;
  renderKategoriOptions("editKategori", p.kategori);
  el("editSatuan").value = p.satuan || "pcs";
  new bootstrap.Modal(document.getElementById("modalEditProduk")).show();
}

function simpanEditProduk() {
  const el = (id) => document.getElementById(id);
  const nama = el("editNama")?.value.trim();
  const harga = parseInt(el("editHarga")?.value) || 0;
  const stok = parseInt(el("editStok")?.value) || 0;
  const kat = el("editKategori")?.value;
  const sat = el("editSatuan")?.value || "pcs";

  if (!nama) {
    showToast("Nama wajib diisi!", "danger");
    return;
  }
  if (harga <= 0) {
    showToast("Harga harus > 0!", "danger");
    return;
  }

  const produk = getProducts();
  const idx = produk.findIndex((p) => p.id === editProdukId);
  if (idx !== -1) {
    produk[idx] = {
      ...produk[idx],
      nama,
      harga,
      stok,
      kategori: kat,
      satuan: sat,
    };
    saveProducts(produk);
    bootstrap.Modal.getInstance(
      document.getElementById("modalEditProduk"),
    )?.hide();
    renderTabelProduk();
    updateStatProduk();
    showToast("Produk berhasil diperbarui!", "success");
  }
}

function hapusProduk(id, nama) {
  showConfirm("Hapus Produk?", `"${nama}" akan dihapus permanen.`, () => {
    saveProducts(getProducts().filter((p) => p.id !== id));
    renderTabelProduk();
    updateStatProduk();
    showToast(`Produk "${nama}" dihapus.`, "info");
  });
}

function eksporProdukExcel() {
  const produk = getProducts();
  if (!produk.length || typeof XLSX === "undefined") {
    showToast("Tidak ada data", "warning");
    return;
  }
  const data = [
    ["No", "ID", "Nama", "Kategori", "Harga", "Stok", "Satuan"],
    ...produk.map((p, i) => [
      i + 1,
      p.id,
      p.nama,
      p.kategori || "-",
      p.harga,
      p.stok,
      p.satuan || "pcs",
    ]),
  ];
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Produk");
  XLSX.writeFile(
    wb,
    `DataProduk_MingMart_${new Date().toLocaleDateString("id-ID").replace(/\//g, "-")}.xlsx`,
  );
  showToast("Ekspor Excel berhasil!", "success");
}

// ============================================================
//  KATEGORI CRUD
// ============================================================
function renderTabelKategori() {
  const tbody = document.getElementById("bodyKategori");
  if (!tbody) return;
  const kat = getKategori();
  const produk = getProducts();
  if (!kat.length) {
    tbody.innerHTML =
      '<tr><td colspan="3" class="text-center py-4 text-muted">Belum ada kategori</td></tr>';
    return;
  }
  tbody.innerHTML = kat
    .map((k, i) => {
      const count = produk.filter((p) => p.kategori === k).length;
      return `<tr>
      <td>${i + 1}</td>
      <td><span class="badge bg-info text-dark fs-6">${k}</span> <small class="text-muted ms-2">${count} produk</small></td>
      <td class="text-center">
        <button class="btn btn-sm btn-warning me-1" onclick="openEditKategori(${i},'${k}')"><i class="bi bi-pencil-fill"></i></button>
        <button class="btn btn-sm btn-danger" onclick="hapusKategori(${i},'${k}')"><i class="bi bi-trash-fill"></i></button>
      </td>
    </tr>`;
    })
    .join("");
}

function tambahKategori() {
  const input = document.getElementById("newKategoriNama");
  const nama = input?.value.trim();
  if (!nama) {
    showToast("Nama kategori wajib diisi!", "danger");
    return;
  }
  const kat = getKategori();
  if (kat.includes(nama)) {
    showToast("Kategori sudah ada!", "warning");
    return;
  }
  kat.push(nama);
  saveKategori(kat);
  if (input) input.value = "";
  renderTabelKategori();
  showToast(`Kategori "${nama}" ditambahkan!`, "success");
}

let editKatIdx = -1;
function openEditKategori(idx, nama) {
  editKatIdx = idx;
  document.getElementById("editKategoriNama").value = nama;
  new bootstrap.Modal(document.getElementById("modalEditKategori")).show();
}

function simpanEditKategori() {
  const nama = document.getElementById("editKategoriNama")?.value.trim();
  if (!nama) {
    showToast("Nama wajib diisi!", "danger");
    return;
  }
  const kat = getKategori();
  const oldNama = kat[editKatIdx];
  kat[editKatIdx] = nama;
  saveKategori(kat);
  // Update produk with old kategori name
  const produk = getProducts();
  produk.forEach((p) => {
    if (p.kategori === oldNama) p.kategori = nama;
  });
  saveProducts(produk);
  bootstrap.Modal.getInstance(
    document.getElementById("modalEditKategori"),
  )?.hide();
  renderTabelKategori();
  showToast("Kategori berhasil diperbarui!", "success");
}

function hapusKategori(idx, nama) {
  const produk = getProducts();
  const count = produk.filter((p) => p.kategori === nama).length;
  const msg =
    count > 0
      ? `"${nama}" digunakan oleh ${count} produk. Produk akan menjadi kategori "Lainnya".`
      : `Kategori "${nama}" akan dihapus.`;
  showConfirm("Hapus Kategori?", msg, () => {
    const kat = getKategori();
    kat.splice(idx, 1);
    saveKategori(kat);
    produk.forEach((p) => {
      if (p.kategori === nama) p.kategori = "Lainnya";
    });
    saveProducts(produk);
    renderTabelKategori();
    showToast(`Kategori "${nama}" dihapus.`, "info");
  });
}

// ============================================================
//  KASIR / POS
// ============================================================
let keranjang = [];
let diskonGlobal = 0;
let totalBelanja = 0;
let daftarProduk = [];

function renderProdukKasir(keyword) {
  const select = document.getElementById("pilihProduk");
  if (!select) return;
  daftarProduk = getProducts();
  let filtered = daftarProduk.filter((p) => p.stok > 0);
  if (keyword && keyword.length > 0) {
    const kw = keyword.toLowerCase();
    filtered = filtered.filter(
      (p) =>
        p.nama.toLowerCase().includes(kw) ||
        p.id.toLowerCase().includes(kw) ||
        (p.kategori || "").toLowerCase().includes(kw),
    );
  }
  select.innerHTML = '<option value="">-- Pilih Produk --</option>';
  filtered.forEach((p) => {
    select.innerHTML += `<option value="${p.id}">${p.nama} — Rp ${p.harga.toLocaleString("id-ID")} (Stok: ${p.stok})</option>`;
  });

  // Render product grid if exists
  const grid = document.getElementById("produkGrid");
  if (grid) {
    grid.innerHTML = "";
    filtered.forEach((p) => {
      const div = document.createElement("div");
      div.className = "col-6 col-md-4 col-lg-3";
      div.innerHTML = `
        <div class="card card-produk h-100 cursor-pointer" onclick="quickAddProduct('${p.id}')">
          <div class="card-body p-2 text-center">
            <div class="rounded-circle bg-primary bg-opacity-10 d-flex align-items-center justify-content-center mx-auto mb-2" style="width:48px;height:48px">
              <i class="bi bi-box-seam text-primary fs-5"></i>
            </div>
            <div class="fw-bold small text-truncate">${p.nama}</div>
            <div class="text-success small fw-bold">Rp ${p.harga.toLocaleString("id-ID")}</div>
            <div class="badge bg-${p.stok <= 5 ? "warning text-dark" : "secondary"} mt-1">Stok: ${p.stok}</div>
          </div>
        </div>`;
      grid.appendChild(div);
    });
    if (filtered.length === 0 && keyword) {
      grid.innerHTML = `<div class="col-12 text-center py-3 text-muted"><i class="bi bi-search fs-4 d-block mb-2"></i>Produk "${keyword}" tidak ditemukan</div>`;
    }
  }
}

function filterProdukKasir() {
  const kw = document.getElementById("searchProdukKasir")?.value || "";
  renderProdukKasir(kw);
  // Clear selection when user types
  const sel = document.getElementById("pilihProduk");
  if (sel) sel.value = "";
  const hp = document.getElementById("hargaProduk");
  if (hp) hp.value = "";
  // Show dropdown while typing
  showProdukDropdown();
}

function showProdukDropdown() {
  const kw = document.getElementById("searchProdukKasir")?.value || "";
  const dl = document.getElementById("produkDropdownList");
  if (!dl) return;
  daftarProduk = getProducts();
  let filtered = daftarProduk.filter((p) => p.stok > 0);
  if (kw.length > 0) {
    const k = kw.toLowerCase();
    filtered = filtered.filter(
      (p) =>
        p.nama.toLowerCase().includes(k) ||
        p.id.toLowerCase().includes(k) ||
        (p.kategori || "").toLowerCase().includes(k)
    );
  }
  if (filtered.length === 0) {
    dl.innerHTML = `<div class="px-3 py-2 text-muted small"><i class="bi bi-search me-1"></i>${kw ? `"${kw}" tidak ditemukan` : "Belum ada produk"}</div>`;
  } else {
    dl.innerHTML = filtered.map((p) => `
      <div class="px-3 py-2 d-flex justify-content-between align-items-center produk-combo-item"
           style="cursor:pointer;border-bottom:1px solid #f0f0f0"
           onmousedown="selectProdukKasir('${p.id}')"
           onmouseover="this.style.background='#f0f6ff'"
           onmouseout="this.style.background=''">
        <div>
          <div class="fw-semibold small">${p.nama}</div>
          <div class="text-muted" style="font-size:0.78rem">${p.kategori || ""}</div>
        </div>
        <div class="text-end">
          <div class="text-success fw-bold small">Rp ${p.harga.toLocaleString("id-ID")}</div>
          <span class="badge ${p.stok <= 5 ? "bg-warning text-dark" : "bg-secondary"}" style="font-size:0.7rem">Stok: ${p.stok}</span>
        </div>
      </div>`).join("");
  }
  dl.classList.remove("d-none");
}

function selectProdukKasir(id) {
  const p = getProducts().find((x) => x.id === id);
  if (!p) return;
  // Set hidden select value
  const sel = document.getElementById("pilihProduk");
  if (sel) sel.value = id;
  // Set search input text
  const inp = document.getElementById("searchProdukKasir");
  if (inp) inp.value = p.nama;
  // Update harga
  const hp = document.getElementById("hargaProduk");
  if (hp) hp.value = p.harga;
  // Show badge terpilih
  const badge = document.getElementById("produkTerpilih");
  const namaEl = document.getElementById("produkTerpilihNama");
  if (badge) badge.classList.remove("d-none");
  if (namaEl) namaEl.textContent = `${p.nama} — Rp ${p.harga.toLocaleString("id-ID")} (Stok: ${p.stok})`;
  // Hide dropdown
  const dl = document.getElementById("produkDropdownList");
  if (dl) dl.classList.add("d-none");
  // Focus jumlah
  document.getElementById("jumlahProduk")?.focus();
}

function clearProdukKasir() {
  const inp = document.getElementById("searchProdukKasir");
  if (inp) inp.value = "";
  const sel = document.getElementById("pilihProduk");
  if (sel) sel.value = "";
  const hp = document.getElementById("hargaProduk");
  if (hp) hp.value = "";
  const badge = document.getElementById("produkTerpilih");
  if (badge) badge.classList.add("d-none");
  const dl = document.getElementById("produkDropdownList");
  if (dl) dl.classList.add("d-none");
  inp?.focus();
}

function quickAddProduct(id) {
  const p = getProducts().find((x) => x.id === id);
  if (!p || p.stok <= 0) {
    showToast("Stok habis!", "warning");
    return;
  }
  const existing = keranjang.find((i) => i.id === id);
  if (existing) {
    if (existing.qty + 1 > p.stok) {
      showToast(`Stok maksimum: ${p.stok}`, "warning");
      return;
    }
    existing.qty++;
    existing.subtotal = existing.harga * existing.qty;
  } else {
    keranjang.push({
      id: p.id,
      nama: p.nama,
      harga: p.harga,
      qty: 1,
      subtotal: p.harga,
    });
  }
  renderKeranjang();
  showToast(`${p.nama} ditambahkan`, "success");
}

function updateHargaOtomatis() {
  const id = document.getElementById("pilihProduk")?.value;
  const el = document.getElementById("hargaProduk");
  const p = getProducts().find((x) => x.id === id);
  if (el) el.value = p ? p.harga : "";
}

function tambahKeKeranjang() {
  const id = document.getElementById("pilihProduk")?.value;
  const qty = parseInt(document.getElementById("jumlahProduk")?.value) || 0;
  const p = getProducts().find((x) => x.id === id);

  if (!p) {
    showToast("Pilih produk terlebih dahulu!", "warning");
    return;
  }
  if (qty <= 0) {
    showToast("Jumlah harus lebih dari 0!", "warning");
    return;
  }
  if (qty > p.stok) {
    showToast(`Stok tidak cukup! Tersedia: ${p.stok}`, "danger");
    return;
  }

  const existing = keranjang.find((i) => i.id === id);
  if (existing) {
    if (existing.qty + qty > p.stok) {
      showToast(`Stok tidak cukup!`, "danger");
      return;
    }
    existing.qty += qty;
    existing.subtotal = existing.harga * existing.qty;
  } else {
    keranjang.push({
      id: p.id,
      nama: p.nama,
      harga: p.harga,
      qty,
      subtotal: p.harga * qty,
    });
  }
  renderKeranjang();
  if (document.getElementById("jumlahProduk"))
    document.getElementById("jumlahProduk").value = "1";
  showToast(`${p.nama} x${qty} ditambahkan`, "success");
}

function renderKeranjang() {
  const tbody = document.getElementById("tabelKeranjang");
  if (!tbody) return;
  if (!keranjang.length) {
    tbody.innerHTML = `<tr><td colspan="5" class="text-center py-4 text-muted"><i class="bi bi-cart-x fs-1 d-block mb-2"></i>Keranjang kosong</td></tr>`;
    updateTotalKeranjang(0);
    return;
  }
  let sub = 0;
  tbody.innerHTML = keranjang
    .map((item, idx) => {
      sub += item.subtotal;
      return `<tr>
      <td><strong class="small">${item.nama}</strong></td>
      <td class="text-center">
        <div class="input-group input-group-sm" style="width:100px">
          <button class="btn btn-outline-secondary btn-sm" onclick="ubahQty(${idx},-1)">−</button>
          <input type="text" class="form-control text-center px-1" value="${item.qty}" readonly>
          <button class="btn btn-outline-secondary btn-sm" onclick="ubahQty(${idx},1)">+</button>
        </div>
      </td>
      <td class="text-end small">Rp ${item.harga.toLocaleString("id-ID")}</td>
      <td class="text-end fw-bold small">Rp ${item.subtotal.toLocaleString("id-ID")}</td>
      <td class="text-center"><button class="btn btn-sm btn-outline-danger" onclick="hapusItemKeranjang(${idx})"><i class="bi bi-x-lg"></i></button></td>
    </tr>`;
    })
    .join("");
  updateTotalKeranjang(sub);
}

function updateTotalKeranjang(sub) {
  const diskon = diskonGlobal || 0;
  const total = Math.max(0, sub - diskon);
  totalBelanja = total;
  const count = keranjang.reduce((s, i) => s + i.qty, 0);
  const e = (id) => document.getElementById(id);
  if (e("subtotalHarga"))
    e("subtotalHarga").textContent = `Rp ${sub.toLocaleString("id-ID")}`;
  if (e("diskonHarga"))
    e("diskonHarga").textContent = `- Rp ${diskon.toLocaleString("id-ID")}`;
  if (e("totalHarga"))
    e("totalHarga").textContent = `Rp ${total.toLocaleString("id-ID")}`;
  if (e("totalHargaSide"))
    e("totalHargaSide").textContent = `Rp ${total.toLocaleString("id-ID")}`;
  if (e("cartCount")) e("cartCount").textContent = count;
  if (e("cartBadge")) e("cartBadge").textContent = `${count} item`;
}

function ubahQty(idx, delta) {
  const item = keranjang[idx];
  const p = getProducts().find((x) => x.id === item.id);
  const newQty = item.qty + delta;
  if (newQty <= 0) {
    hapusItemKeranjang(idx);
    return;
  }
  if (p && newQty > p.stok) {
    showToast(`Stok max: ${p.stok}`, "warning");
    return;
  }
  keranjang[idx].qty = newQty;
  keranjang[idx].subtotal = item.harga * newQty;
  renderKeranjang();
}

function hapusItemKeranjang(idx) {
  keranjang.splice(idx, 1);
  renderKeranjang();
}

function bersihkanKeranjang() {
  if (!keranjang.length) return;
  showConfirm("Bersihkan Keranjang?", "Semua item akan dihapus.", () => {
    keranjang = [];
    diskonGlobal = 0;
    renderKeranjang();
    showToast("Keranjang dikosongkan", "info");
  });
}

function terapkanDiskon() {
  const val = parseInt(document.getElementById("inputDiskon")?.value) || 0;
  const sub = keranjang.reduce((s, i) => s + i.subtotal, 0);
  if (val < 0 || val > sub) {
    showToast("Diskon tidak valid!", "danger");
    return;
  }
  diskonGlobal = val;
  renderKeranjang();
  showToast(`Diskon Rp ${val.toLocaleString("id-ID")} diterapkan`, "success");
}

function prosesBayar() {
  if (!keranjang.length) {
    showToast("Keranjang masih kosong!", "warning");
    return;
  }
  totalBelanja = Math.max(
    0,
    keranjang.reduce((s, i) => s + i.subtotal, 0) - diskonGlobal,
  );
  const m = document.getElementById("modalBayar");
  if (m) {
    document.getElementById("modalTotalTagihan").textContent =
      `Rp ${totalBelanja.toLocaleString("id-ID")}`;
    document.getElementById("nominalBayar").value = "";
    document.getElementById("metodeBayar").value = "Cash";
    document.getElementById("namaPembeli").value = "";
    document.getElementById("textKembalian").textContent = "Rp 0";
    const grp = document.getElementById("groupUangBayar");
    if (grp) grp.style.display = "block";
    new bootstrap.Modal(m).show();
    setTimeout(() => document.getElementById("nominalBayar")?.focus(), 400);
  }
}

function hitungKembalian() {
  const bayar = parseInt(document.getElementById("nominalBayar")?.value) || 0;
  const el = document.getElementById("textKembalian");
  const kembali = bayar - totalBelanja;
  if (el) {
    el.textContent = `Rp ${kembali.toLocaleString("id-ID")}`;
    el.className = kembali < 0 ? "text-danger fw-bold" : "text-success fw-bold";
  }
}

function toggleInputUang() {
  const metode = document.getElementById("metodeBayar")?.value;
  const nomEl = document.getElementById("nominalBayar");
  const grp = document.getElementById("groupUangBayar");
  if (!nomEl) return;
  if (metode === "QRIS" || metode === "Transfer" || metode === "Hutang") {
    nomEl.value = totalBelanja;
    nomEl.readOnly = true;
    if (grp) grp.style.opacity = "0.6";
  } else {
    nomEl.value = "";
    nomEl.readOnly = false;
    if (grp) grp.style.opacity = "1";
    nomEl.focus();
  }
  hitungKembalian();
}

async function konfirmasiBayar() {
  const nominal = parseInt(document.getElementById("nominalBayar")?.value) || 0;
  const total = totalBelanja;
  const metode = document.getElementById("metodeBayar")?.value || "Cash";
  const pembeli =
    document.getElementById("namaPembeli")?.value.trim() || "Umum";

  if (nominal < total && metode !== "Hutang") {
    showToast("Uang pembayaran kurang!", "danger");
    return;
  }

  bootstrap.Modal.getInstance(document.getElementById("modalBayar"))?.hide();

  // Simpan riwayat
  const riwayat = JSON.parse(localStorage.getItem(DB_RIWAYAT)) || [];
  const trxId = "TRX-" + Date.now();
  const trx = {
    id: trxId,
    waktu: new Date().toLocaleString("id-ID"),
    items: [...keranjang],
    total,
    diskon: diskonGlobal,
    metode,
    pembeli,
  };
  riwayat.unshift(trx);
  localStorage.setItem(DB_RIWAYAT, JSON.stringify(riwayat));

  // Handle hutang
  if (metode === "Hutang") {
    const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
    hutang.unshift({
      id: "HT-" + Date.now(),
      trxId,
      pembeli,
      total,
      waktu: trx.waktu,
      status: "Belum Lunas",
      catatan: "",
    });
    localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
  }

  // Kurangi stok
  const produk = getProducts();
  keranjang.forEach((item) => {
    const p = produk.find((x) => x.id === item.id);
    if (p) p.stok = Math.max(0, p.stok - item.qty);
  });
  saveProducts(produk);

  const snap = [...keranjang],
    snapDiskon = diskonGlobal;
  keranjang = [];
  diskonGlobal = 0;
  if (document.getElementById("inputDiskon"))
    document.getElementById("inputDiskon").value = "";
  renderKeranjang();
  renderProdukKasir();

  showToast("Transaksi berhasil! Stok diperbarui.", "success");

  // Pilih cetak
  const pil = await pilihanCetak();
  if (!pil) return;
  if (pil === "pdf")
    cetakPDF(total, metode, nominal, "simpan", pembeli, snap, snapDiskon);
  if (pil === "print")
    cetakPDF(total, metode, nominal, "cetak", pembeli, snap, snapDiskon);
  if (pil === "bluetooth")
    cetakBluetooth(total, metode, nominal, pembeli, snap, snapDiskon);
}

function pilihanCetak() {
  return new Promise((resolve) => {
    let m = document.getElementById("modalPilihanCetak");
    if (!m) {
      m = document.createElement("div");
      m.id = "modalPilihanCetak";
      m.className = "modal fade";
      m.setAttribute("tabindex", "-1");
      m.innerHTML = `
        <div class="modal-dialog modal-dialog-centered">
          <div class="modal-content">
            <div class="modal-header"><h5 class="modal-title"><i class="bi bi-printer-fill me-2"></i>Pilih Metode Cetak</h5>
              <button type="button" class="btn-close" data-bs-dismiss="modal"></button></div>
            <div class="modal-body">
              <div class="row g-3">
                <div class="col-6"><button class="btn btn-warning w-100 py-3" id="btnCetakPDF"><i class="bi bi-file-pdf-fill d-block fs-3 mb-1"></i>Simpan PDF</button></div>
                <div class="col-6"><button class="btn btn-primary w-100 py-3" id="btnCetakPrint"><i class="bi bi-printer-fill d-block fs-3 mb-1"></i>Cetak Printer</button></div>
                <div class="col-6"><button class="btn btn-success w-100 py-3" id="btnCetakBT"><i class="bi bi-bluetooth d-block fs-3 mb-1"></i>Bluetooth</button></div>
                <div class="col-6"><button class="btn btn-secondary w-100 py-3" id="btnCetakSkip"><i class="bi bi-x-circle d-block fs-3 mb-1"></i>Lewati</button></div>
              </div>
            </div>
          </div>
        </div>`;
      document.body.appendChild(m);
    }
    const bsM = new bootstrap.Modal(m);
    bsM.show();
    const hide = (val) => {
      bsM.hide();
      resolve(val);
    };
    document.getElementById("btnCetakPDF").onclick = () => hide("pdf");
    document.getElementById("btnCetakPrint").onclick = () => hide("print");
    document.getElementById("btnCetakBT").onclick = () => hide("bluetooth");
    document.getElementById("btnCetakSkip").onclick = () => hide(null);
  });
}

// ============================================================
//  CETAK STRUK
// ============================================================
function getJsPDF() {
  return (window.jspdf && window.jspdf.jsPDF) || window.jsPDF || null;
}

async function cetakPDF(
  total,
  metode,
  bayar,
  aksi,
  pembeli,
  items,
  diskon = 0,
) {
  try {
    showToast("Menyiapkan struk...", "info");
    const JsPDF = await new Promise((res, rej) => {
      const t = Date.now();
      const c = () => {
        const v = getJsPDF();
        if (v) res(v);
        else if (Date.now() - t > 8000) rej();
        else setTimeout(c, 200);
      };
      c();
    });
    const acc = JSON.parse(localStorage.getItem(DB_ADMIN)) || {};
    const kembali = bayar - total;
    const now = new Date().toLocaleString("id-ID");
    const doc = new JsPDF({ unit: "mm", format: [80, 240] });

    // === LOGO ===
    let logoY = 8;
    try {
      if (LOGO_TOKO_B64) {
        doc.addImage(
          LOGO_TOKO_B64,
          "PNG",
          28,
          logoY,
          24,
          24,
          undefined,
          "FAST",
        );
        logoY = 36;
      }
    } catch (e) {
      logoY = 8;
    }

    doc.setFontSize(13);
    doc.setFont("helvetica", "bold");
    doc.text("MING MART", 40, logoY + 2, { align: "center" });
    doc.setFontSize(7);
    doc.setFont("helvetica", "normal");
    doc.text("Dusun Batu Menjangkong, Desa Anyar", 40, logoY + 7, {
      align: "center",
    });
    doc.text("Kec. Bayan, Kab. Lombok Utara", 40, logoY + 11, {
      align: "center",
    });
    doc.setLineDashPattern([1, 1], 0);
    doc.line(5, logoY + 14, 75, logoY + 14);

    let y = logoY + 20;
    [
      ["Pembeli", pembeli],
      ["Tanggal", now],
      ["Pembayaran", metode],
      ["Kasir", acc.username || "admin"],
    ].forEach(([l, v]) => {
      doc.setFontSize(8);
      doc.text(l, 5, y);
      doc.text(String(v), 75, y, { align: "right" });
      y += 5;
    });
    doc.line(5, y, 75, y);
    y += 6;

    items.forEach((item) => {
      doc.setFont("helvetica", "bold");
      doc.setFontSize(8);
      doc.text(item.nama, 5, y);
      doc.text(`Rp ${item.subtotal.toLocaleString("id-ID")}`, 75, y, {
        align: "right",
      });
      y += 5;
      doc.setFont("helvetica", "normal");
      doc.setFontSize(7);
      doc.text(
        `  ${item.qty} x Rp ${item.harga.toLocaleString("id-ID")}`,
        5,
        y,
      );
      y += 6;
    });

    doc.line(5, y - 2, 75, y - 2);
    y += 4;
    if (diskon > 0) {
      doc.setFontSize(8);
      doc.text("Subtotal", 5, y);
      doc.text(`Rp ${(total + diskon).toLocaleString("id-ID")}`, 75, y, {
        align: "right",
      });
      y += 5;
      doc.text("Diskon", 5, y);
      doc.text(`- Rp ${diskon.toLocaleString("id-ID")}`, 75, y, {
        align: "right",
      });
      y += 5;
    }
    doc.setFont("helvetica", "bold");
    doc.setFontSize(10);
    doc.text("TOTAL", 5, y);
    doc.text(`Rp ${total.toLocaleString("id-ID")}`, 75, y, { align: "right" });
    y += 6;
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("Bayar", 5, y);
    doc.text(`Rp ${bayar.toLocaleString("id-ID")}`, 75, y, { align: "right" });
    y += 5;
    doc.text("Kembali", 5, y);
    doc.text(`Rp ${kembali.toLocaleString("id-ID")}`, 75, y, {
      align: "right",
    });
    y += 12;
    doc.setFontSize(8);
    doc.text("Terima kasih sudah berbelanja di Ming Mart!", 40, y, {
      align: "center",
    });
    y += 5;
    doc.setFontSize(7);
    doc.text("* Simpan struk ini sebagai bukti pembelian *", 40, y, {
      align: "center",
    });

    if (aksi === "simpan") doc.save(`Struk-MingMart-${Date.now()}.pdf`);
    else {
      const url = doc.output("bloburl");
      const f = document.createElement("iframe");
      f.style.display = "none";
      f.src = url;
      document.body.appendChild(f);
      f.onload = () => {
        f.contentWindow.print();
        setTimeout(() => f.remove(), 1000);
      };
    }
    showToast("Struk berhasil!", "success");
  } catch (e) {
    showToast("Gagal buat struk: " + e.message, "danger");
  }
}

async function cetakBluetooth(
  total,
  metode,
  bayar,
  pembeli,
  items,
  diskon = 0,
) {
  if (!navigator.bluetooth) {
    showToast("Browser tidak support Bluetooth", "danger");
    return;
  }
  try {
    const device = await navigator.bluetooth.requestDevice({
      filters: [{ services: ["000018f0-0000-1000-8000-00805f9b34fb"] }],
    });
    const server = await device.gatt.connect();
    const service = await server.getPrimaryService(
      "000018f0-0000-1000-8000-00805f9b34fb",
    );
    const char = await service.getCharacteristic(
      "00002af1-0000-1000-8000-00805f9b34fb",
    );
    const teks = buatTeksStruk(total, metode, bayar, pembeli, items, diskon);
    const data = new TextEncoder().encode(teks);
    for (let i = 0; i < data.length; i += 20)
      await char.writeValue(data.slice(i, i + 20));
    device.gatt.disconnect();
    showToast("Cetak Bluetooth berhasil!", "success");
  } catch (e) {
    showToast("Gagal cetak Bluetooth: " + e.message, "danger");
  }
}

function buatTeksStruk(total, metode, bayar, pembeli, items, diskon) {
  const acc = JSON.parse(localStorage.getItem(DB_ADMIN)) || {};
  const kembali = bayar - total;
  const now = new Date().toLocaleString("id-ID");
  const garis = "--------------------------------\n";
  const center = (s) =>
    " ".repeat(Math.max(0, Math.floor((32 - s.length) / 2))) + s + "\n";
  let t =
    "\x1B\x40" +
    center("MING MART") +
    center("Desa Anyar, Lombok Utara") +
    garis;
  t +=
    `Pembeli : ${pembeli}\nTanggal : ${now}\nKasir   : ${acc.username || "admin"}\nMetode  : ${metode}\n` +
    garis;
  items.forEach((i) => {
    t += `${i.nama.substring(0, 20).padEnd(20)}${`Rp ${i.subtotal.toLocaleString("id-ID")}`.padStart(12)}\n  ${i.qty} x Rp ${i.harga.toLocaleString("id-ID")}\n`;
  });
  t += garis;
  if (diskon > 0) {
    t += `Subtotal  : Rp ${(total + diskon).toLocaleString("id-ID")}\nDiskon    : Rp ${diskon.toLocaleString("id-ID")}\n`;
  }
  t += `\x1B\x21\x08TOTAL     : Rp ${total.toLocaleString("id-ID")}\n\x1B\x21\x00`;
  t +=
    `Bayar     : Rp ${bayar.toLocaleString("id-ID")}\nKembali   : Rp ${kembali.toLocaleString("id-ID")}\n` +
    garis +
    center("Terima kasih!") +
    "\n\n\n\x1D\x56\x41";
  return t;
}

