function renderDashboard() {
  const riwayat = JSON.parse(localStorage.getItem(DB_RIWAYAT)) || [];
  const tbody = document.getElementById("bodyRiwayat");

  let totalOmzet = 0,
    totalTerjual = 0,
    totalHutang = 0;
  const dataProduk = {};

  if (!riwayat.length) {
    if (tbody)
      tbody.innerHTML = `<tr><td colspan="7" class="text-center py-4 text-muted"><i class="bi bi-bar-chart fs-1 d-block mb-2"></i>Belum ada transaksi</td></tr>`;
    ["totalOmzet", "totalTerjual", "totalTransaksi", "totalHutang"].forEach(
      (id) => {
        const el = document.getElementById(id);
        if (el)
          el.textContent =
            id.includes("Omzet") || id.includes("Hutang") ? "Rp 0" : "0";
      },
    );
    renderGrafik({});
    return;
  }

  if (tbody)
    tbody.innerHTML = riwayat
      .map((t) => {
        totalOmzet += t.total;
        if (t.metode === "Hutang") totalHutang += t.total;
        t.items.forEach((i) => {
          totalTerjual += i.qty;
          dataProduk[i.nama] = (dataProduk[i.nama] || 0) + i.qty;
        });
        const badge =
          t.metode === "Hutang"
            ? "danger"
            : t.metode === "QRIS"
              ? "warning text-dark"
              : t.metode === "Transfer"
                ? "info text-dark"
                : "success";
        return `<tr>
      <td class="small">${t.waktu}</td>
      <td><span class="badge bg-primary">${t.id}</span></td>
      <td>${t.pembeli || "-"}</td>
      <td><span class="badge bg-${badge}">${t.metode}</span></td>
      <td class="text-end fw-bold">Rp ${t.total.toLocaleString("id-ID")}</td>
      <td class="text-end small text-muted">Rp ${(t.diskon || 0).toLocaleString("id-ID")}</td>
      <td class="text-center">
        <button class="btn btn-xs btn-sm btn-info me-1" onclick="lihatDetail('${t.id}')" title="Detail"><i class="bi bi-eye-fill"></i></button>
        <button class="btn btn-xs btn-sm btn-warning me-1" onclick="editLaporan('${t.id}',${t.total})" title="Edit"><i class="bi bi-pencil-fill"></i></button>
        <button class="btn btn-xs btn-sm btn-danger me-1" onclick="hapusTransaksi('${t.id}')" title="Hapus"><i class="bi bi-trash-fill"></i></button>
        <button class="btn btn-xs btn-sm btn-secondary" onclick="cetakUlang('${t.id}')" title="Cetak ulang"><i class="bi bi-printer-fill"></i></button>
      </td>
    </tr>`;
      })
      .join("");

  const e = (id) => document.getElementById(id);
  if (e("totalOmzet"))
    e("totalOmzet").textContent = `Rp ${totalOmzet.toLocaleString("id-ID")}`;
  if (e("totalTerjual")) e("totalTerjual").textContent = `${totalTerjual} Item`;
  if (e("totalTransaksi")) e("totalTransaksi").textContent = riwayat.length;
  if (e("totalHutang"))
    e("totalHutang").textContent = `Rp ${totalHutang.toLocaleString("id-ID")}`;
  renderGrafik(dataProduk);
}

function renderGrafik(data) {
  const canvas = document.getElementById("chartPenjualan");
  if (!canvas || typeof Chart === "undefined") return;
  if (window._chart) window._chart.destroy();
  const labels = Object.keys(data),
    values = Object.values(data);
  if (!labels.length) return;
  const colors = [
    "#0d6efd",
    "#198754",
    "#ffc107",
    "#dc3545",
    "#6f42c1",
    "#0dcaf0",
    "#fd7e14",
  ];
  window._chart = new Chart(canvas, {
    type: "bar",
    data: {
      labels,
      datasets: [
        {
          label: "Unit Terjual",
          data: values,
          backgroundColor: colors.map((c) => c + "99"),
          borderColor: colors,
          borderWidth: 2,
          borderRadius: 6,
        },
      ],
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } },
    },
  });
}

function lihatDetail(id) {
  const t = (JSON.parse(localStorage.getItem(DB_RIWAYAT)) || []).find(
    (x) => x.id === id,
  );
  if (!t) return;
  const e = (k) => document.getElementById(k);
  e("detailId").textContent = t.id;
  e("detailWaktu").textContent = t.waktu;
  e("detailPembeli").textContent = t.pembeli || "-";
  e("detailMetode").textContent = t.metode;
  e("detailTotal").textContent = `Rp ${t.total.toLocaleString("id-ID")}`;
  e("detailDiskon").textContent =
    `Rp ${(t.diskon || 0).toLocaleString("id-ID")}`;
  e("detailItems").innerHTML = t.items
    .map(
      (i) => `
    <tr><td>${i.nama}</td><td class="text-center">${i.qty}</td>
    <td class="text-end">Rp ${i.harga.toLocaleString("id-ID")}</td>
    <td class="text-end fw-bold">Rp ${i.subtotal.toLocaleString("id-ID")}</td></tr>`,
    )
    .join("");
  new bootstrap.Modal(document.getElementById("modalDetailTrx")).show();
}

function editLaporan(id, total) {
  document.getElementById("editTrxId").value = id;
  document.getElementById("editTrxTotal").value = total;
  new bootstrap.Modal(document.getElementById("modalEditTrx")).show();
}

function simpanEditLaporan() {
  const id = document.getElementById("editTrxId").value;
  const total = parseInt(document.getElementById("editTrxTotal").value) || 0;
  if (total <= 0) {
    showToast("Total harus > 0", "danger");
    return;
  }
  const riwayat = JSON.parse(localStorage.getItem(DB_RIWAYAT)) || [];
  const idx = riwayat.findIndex((t) => t.id === id);
  if (idx !== -1) {
    riwayat[idx].total = total;
    localStorage.setItem(DB_RIWAYAT, JSON.stringify(riwayat));
    bootstrap.Modal.getInstance(
      document.getElementById("modalEditTrx"),
    )?.hide();
    renderDashboard();
    showToast("Transaksi diperbarui!", "success");
  }
}

function hapusTransaksi(id) {
  showConfirm("Hapus Transaksi?", "Data ini akan dihapus permanen.", () => {
    const r = (JSON.parse(localStorage.getItem(DB_RIWAYAT)) || []).filter(
      (t) => t.id !== id,
    );
    localStorage.setItem(DB_RIWAYAT, JSON.stringify(r));
    renderDashboard();
    showToast("Transaksi dihapus.", "info");
  });
}

function cetakUlang(id) {
  const t = (JSON.parse(localStorage.getItem(DB_RIWAYAT)) || []).find(
    (x) => x.id === id,
  );
  if (!t) return;
  cetakPDF(
    t.total,
    t.metode,
    t.total,
    "cetak",
    t.pembeli || "Umum",
    t.items,
    t.diskon || 0,
  );
}

function resetLaporan() {
  showConfirm(
    "Reset Semua Data?",
    "Seluruh riwayat transaksi akan dihapus permanen!",
    () => {
      localStorage.removeItem(DB_RIWAYAT);
      renderDashboard();
      showToast("Semua riwayat dihapus.", "warning");
    },
  );
}

// ============================================================
//  EKSPOR LAPORAN EXCEL
// ============================================================
function eksporLaporanExcel(tipe = "semua") {
  if (typeof XLSX === "undefined") {
    showToast("Library Excel tidak tersedia", "danger");
    return;
  }
  const riwayat = JSON.parse(localStorage.getItem(DB_RIWAYAT)) || [];
  const produk = getProducts();
  const wb = XLSX.utils.book_new();

  if (tipe === "transaksi" || tipe === "semua") {
    const data = [
      ["ID", "Waktu", "Pembeli", "Metode", "Total", "Diskon"],
      ...riwayat.map((t) => [
        t.id,
        t.waktu,
        t.pembeli || "-",
        t.metode,
        t.total,
        t.diskon || 0,
      ]),
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(data), "Riwayat");
  }
  if (tipe === "produk" || tipe === "semua") {
    const data = [
      ["ID", "Nama", "Kategori", "Harga", "Stok", "Satuan"],
      ...produk.map((p) => [
        p.id,
        p.nama,
        p.kategori || "-",
        p.harga,
        p.stok,
        p.satuan || "pcs",
      ]),
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(data), "Produk");
  }
  if (tipe === "hutang" || tipe === "semua") {
    const hutang = riwayat.filter((t) => t.metode === "Hutang");
    const data = [
      ["ID", "Waktu", "Pembeli", "Total"],
      ...hutang.map((t) => [t.id, t.waktu, t.pembeli || "-", t.total]),
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(data), "Hutang");
  }
  if (tipe === "pengeluaran" || tipe === "semua") {
    const pengeluaran = JSON.parse(localStorage.getItem(DB_PENGELUARAN)) || [];
    const data = [
      ["No", "Tanggal", "Keterangan", "Kategori", "Produk Stok", "Jumlah Stok", "Jumlah (Rp)"],
      ...pengeluaran.map((p, i) => [
        i + 1,
        new Date(p.tanggal).toLocaleDateString("id-ID"),
        p.keterangan,
        p.kategori || "Umum",
        p.stokProdukNama || "-",
        p.stokJumlah || 0,
        p.jumlah,
      ]),
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(data), "Pengeluaran");
  }

  XLSX.writeFile(
    wb,
    `LaporanMingMart_${new Date().toLocaleDateString("id-ID").replace(/\//g, "-")}.xlsx`,
  );
  showToast("Ekspor Excel berhasil!", "success");
}

// ============================================================
//  MANAJEMEN HUTANG
// ============================================================
function renderTabelHutang(keyword = "") {
  const tbody = document.getElementById("bodyHutang");
  if (!tbody) return;
  let hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
  if (keyword)
    hutang = hutang.filter(
      (h) =>
        h.pembeli.toLowerCase().includes(keyword.toLowerCase()) ||
        h.id.toLowerCase().includes(keyword.toLowerCase()),
    );

  if (!hutang.length) {
    tbody.innerHTML = `<tr><td colspan="7" class="text-center py-4 text-muted"><i class="bi bi-check-circle fs-1 d-block mb-2 text-success"></i>${keyword ? "Tidak ditemukan" : "Tidak ada hutang"}</td></tr>`;
    return;
  }

  let totalHutang = 0;
  tbody.innerHTML = hutang
    .map((h, i) => {
      if (h.status !== "Lunas") totalHutang += h.total;
      const badge = h.status === "Lunas" ? "bg-success" : "bg-danger";
      return `<tr class="${h.status === "Lunas" ? "table-success opacity-75" : ""}">
      <td>${i + 1}</td>
      <td><span class="badge bg-warning text-dark">${h.id}</span></td>
      <td><strong>${h.pembeli}</strong></td>
      <td class="small text-muted">${h.waktu}</td>
      <td class="text-end fw-bold">Rp ${h.total.toLocaleString("id-ID")}</td>
      <td><span class="badge ${badge}">${h.status}</span></td>
      <td class="text-center">
        ${h.status !== "Lunas" ? `<button class="btn btn-sm btn-success me-1" onclick="lunasHutang('${h.id}')" title="Tandai Lunas"><i class="bi bi-check-circle-fill"></i></button>` : ""}
        <button class="btn btn-sm btn-warning me-1" onclick="editHutang('${h.id}')" title="Edit"><i class="bi bi-pencil-fill"></i></button>
        <button class="btn btn-sm btn-danger" onclick="hapusHutang('${h.id}')" title="Hapus"><i class="bi bi-trash-fill"></i></button>
      </td>
    </tr>`;
    })
    .join("");

  const el = document.getElementById("totalHutangAktif");
  if (el) el.textContent = `Rp ${totalHutang.toLocaleString("id-ID")}`;
}

function lunasHutang(id) {
  showConfirm(
    "Tandai Lunas?",
    "Hutang ini akan ditandai sebagai lunas.",
    () => {
      const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
      const idx = hutang.findIndex((h) => h.id === id);
      if (idx !== -1) {
        hutang[idx].status = "Lunas";
        localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
        renderTabelHutang();
        showToast("Hutang ditandai lunas!", "success");
      }
    },
  );
}

let editHutangId = null;
function editHutang(id) {
  const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
  const h = hutang.find((x) => x.id === id);
  if (!h) return;
  editHutangId = id;
  document.getElementById("editHutangPembeli").value = h.pembeli;
  document.getElementById("editHutangTotal").value = h.total;
  document.getElementById("editHutangCatatan").value = h.catatan || "";
  document.getElementById("editHutangStatus").value = h.status;
  new bootstrap.Modal(document.getElementById("modalEditHutang")).show();
}

function simpanEditHutang() {
  const pembeli = document.getElementById("editHutangPembeli").value.trim();
  const total = parseInt(document.getElementById("editHutangTotal").value) || 0;
  const catatan = document.getElementById("editHutangCatatan").value.trim();
  const status = document.getElementById("editHutangStatus").value;
  if (!pembeli) {
    showToast("Nama pembeli wajib!", "danger");
    return;
  }
  if (total <= 0) {
    showToast("Total harus > 0", "danger");
    return;
  }
  const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
  const idx = hutang.findIndex((h) => h.id === editHutangId);
  if (idx !== -1) {
    hutang[idx] = { ...hutang[idx], pembeli, total, catatan, status };
    localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
    bootstrap.Modal.getInstance(
      document.getElementById("modalEditHutang"),
    )?.hide();
    renderTabelHutang();
    showToast("Hutang diperbarui!", "success");
  }
}

function hapusHutang(id) {
  showConfirm("Hapus Hutang?", "Data hutang ini akan dihapus permanen.", () => {
    const hutang = (JSON.parse(localStorage.getItem(DB_HUTANG)) || []).filter(
      (h) => h.id !== id,
    );
    localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
    renderTabelHutang();
    showToast("Hutang dihapus.", "info");
  });
}

function tambahHutangManual() {
  const pembeli = document.getElementById("newHutangPembeli")?.value.trim();
  const total = parseInt(document.getElementById("newHutangTotal")?.value) || 0;
  const catatan =
    document.getElementById("newHutangCatatan")?.value.trim() || "";
  if (!pembeli) {
    showToast("Nama pembeli wajib!", "danger");
    return;
  }
  if (total <= 0) {
    showToast("Total harus > 0", "danger");
    return;
  }
  const hutang = JSON.parse(localStorage.getItem(DB_HUTANG)) || [];
  hutang.unshift({
    id: "HT-" + Date.now(),
    trxId: "",
    pembeli,
    total,
    waktu: new Date().toLocaleString("id-ID"),
    status: "Belum Lunas",
    catatan,
  });
  localStorage.setItem(DB_HUTANG, JSON.stringify(hutang));
  document.getElementById("newHutangPembeli").value = "";
  document.getElementById("newHutangTotal").value = "";
  if (document.getElementById("newHutangCatatan"))
    document.getElementById("newHutangCatatan").value = "";
  renderTabelHutang();
  showToast("Hutang berhasil dicatat!", "success");
}
